"""
Wide Source Synthesis — Romans chapters 12–13
bookId: romans
Run: python3 scripts/ws-synthesis-romans-12-13.py

Sources used: calvin, ellicott, clarke, wesley, barnes, rwp
  (mhcc not found for Romans; jfb file contains Acts content — both omitted)
Chapter range: 12–13  (21 + 14 = 35 verses)

Key synthesis decisions:
- v12:2 "conformed/transformed": two distinct Greek verbs (συσχηματίζω vs. μεταμορφόω);
  Ellicott specifies the difference. Consensus: affirm.
- v12:19 "give place to wrath": commentators are united that "the wrath" here is God's wrath
  (note Greek article), not the believer's own anger. Consensus: affirm.
- v12:20 "coals of fire": Two main readings — (a) shame/melt the enemy into repentance;
  (b) heap the vengeance of God on him by making him more culpable. Consensus: mixed.
- v13:1 governing authorities: All sources agree on the principle; none address the limits
  of civil disobedience in this passage. Consensus: affirm.
- v13:11-14: Eschatological urgency; "put on Christ" as armor. Consensus: affirm.
- Missing keys: calvin ch12 missing v5,v7; wesley ch12 missing v4,v14,v16,v18;
  rwp ch12 missing v8; wesley ch13 missing v12. Use closest section entries.
"""

import json, pathlib

ROOT = pathlib.Path(__file__).parent.parent

def load_synthesis(book):
    p = ROOT / 'data' / 'commentary' / 'synthesis' / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_synthesis(book, data):
    p = ROOT / 'data' / 'commentary' / 'synthesis' / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_synthesis(existing, new_data):
    """Merge new chapter/verse entries without overwriting existing ones."""
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, entry in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = entry

